class InversionsCounter
{
    static int countInversions(int[] array)
    {
        if (array == null || array.length == 0) {
            return 0;
        }
        int[] copy = array.clone();
        return mergeSort(copy, copy.length);
    }


    /* This method sorts the input array and returns the
       number of inversions in the array */
    static int mergeSort(int arr[], int array_size)
    {
        int temp[] = new int[array_size];
        return _mergeSort(arr, temp, 0, array_size - 1);
    }

    /* An auxiliary recursive method that sorts the input array and
      returns the number of inversions in the array. */
    static int _mergeSort(int arr[], int temp[], int left, int right)
    {
      int mid, inv_count = 0;
      if (right > left)
      {
        /* Divide the array into two parts and call _mergeSortAndCountInv()
           for each of the parts */
        mid = (right + left)/2;

        /* Inversion count will be sum of inversions in left-part, right-part
          and number of inversions in merging */
        inv_count  = _mergeSort(arr, temp, left, mid);
        inv_count += _mergeSort(arr, temp, mid+1, right);

        /*Merge the two parts*/
        inv_count += merge(arr, temp, left, mid+1, right);
      }
      return inv_count;
    }

    /* This method merges two sorted arrays and returns inversion count in
       the arrays.*/
    static int merge(int arr[], int temp[], int left, int mid, int right)
    {
      int i, j, k;
      int inv_count = 0;

      i = left; /* i is index for left subarray*/
      j = mid;  /* j is index for right subarray*/
      k = left; /* k is index for resultant merged subarray*/
      while ((i <= mid - 1) && (j <= right))
      {
        if (arr[i] <= arr[j])
        {
          temp[k++] = arr[i++];
        }
        else
        {
          temp[k++] = arr[j++];

         /*this is tricky -- see above explanation/diagram for merge()*/
          inv_count = inv_count + (mid - i);
        }
      }

      /* Copy the remaining elements of left subarray
       (if there are any) to temp*/
      while (i <= mid - 1)
        temp[k++] = arr[i++];

      /* Copy the remaining elements of right subarray
       (if there are any) to temp*/
      while (j <= right)
        temp[k++] = arr[j++];

      /*Copy back the merged elements to original array*/
      for (i=left; i <= right; i++)
        arr[i] = temp[i];

      return inv_count;
    }

    // Driver method to test the above function
    public static void main(String[] args) 
    {
        int arr[] = new int[]{1, 20, 6, 4, 5};
        System.out.println("Number of inversions are " + mergeSort(arr, 5));

    }
}

fun countInversions(arr: IntArray): Int {
    val temp = IntArray(arr.size)
    return mergeSortCount(arr, temp, 0, arr.size - 1)
}

fun mergeSortCount(arr: IntArray, temp: IntArray, left: Int, right: Int): Int {
    var invCount = 0
    if (left < right) {
        val mid = (left + right) / 2
        invCount += mergeSortCount(arr, temp, left, mid)
        invCount += mergeSortCount(arr, temp, mid + 1, right)
        invCount += merge(arr, temp, left, mid + 1, right)
    }
    return invCount
}

fun merge(arr: IntArray, temp: IntArray, left: Int, mid: Int, right: Int): Int {
    var i = left
    var j = mid
    var k = left
    var invCount = 0

    while (i < mid && j <= right) {
        if (arr[i] <= arr[j]) {
            temp[k++] = arr[i++]
        } else {
            temp[k++] = arr[j++]
            invCount += (mid - i)
        }
    }
    while (i < mid) temp[k++] = arr[i++]
    while (j <= right) temp[k++] = arr[j++]
    for (idx in left..right) arr[idx] = temp[idx]

    return invCount
}

